function.arguments:
{"script":"#!/bin/bash
cd ~/test_directory 2>/dev/null || { echo "0"; exit 0; }
total=$(find . -maxdepth 1 -type f -printf "%s\n" | awk '{s+=$1} END{print s+0}')
kb=$(( (total + 1023) / 1024 ))
echo "$kb""}

{"script":"#!/bin/bash
cd ~/test_directory 2>/dev/null || { echo "0"; exit 0; }
total_bytes=$(find . -maxdepth 1 -type f -printf "%s\n" | awk '{s+=$1} END{print s+0}')
if [ -z "$total_bytes" ]; then total_bytes=0; fi
kb=$(( total_bytes / 1024 ))
echo "$kb""}
